import jwt
import requests

class JWTLib:
  def __init__(self, algorithm):
    self._algorithm = algorithm

  def verify(self, token):
    try:
      return (jwt.decode(token, algorithms=[self._algorithm]))['payload']
    except:
      print('Invalid token')


